const e=[{id:1,section:"幼兒園高班",sectionName:"語文與認知",category:"反義詞",question:"「大」的反義詞是什麼？",options:["多","小","高","長"],correctAnswer:1,explanation:"「大」和「小」是一對相反詞。"},{id:2,section:"幼兒園高班",sectionName:"語文與認知",category:"量詞運用",question:"一（ ）小鳥在天上飛。括號裡應該填什麼？",options:["條","個","隻","張"],correctAnswer:2,explanation:"計算鳥類或多數動物時，我們用量詞「隻」。"},{id:3,section:"幼兒園高班",sectionName:"基礎數學",category:"數數與加法",question:"小明有 2 顆糖果，媽媽又給了他 3 顆，小明現在一共有幾顆糖果？",options:["4 顆","5 顆","6 顆","7 顆"],correctAnswer:1,explanation:"2 加上 3 等於 5。"},{id:4,section:"幼兒園高班",sectionName:"邏輯與常識",category:"自然常識",question:"哪一種動物會「汪汪」叫？",options:["小貓","小狗","小鴨","小羊"],correctAnswer:1,explanation:"小狗的叫聲是「汪汪」。"},{id:5,section:"幼兒園高班",sectionName:"基礎數學",category:"減法運算",question:"樹上有 5 只小鳥，飛走了 2 只，還剩幾只？",options:["2 只","3 只","4 只","5 只"],correctAnswer:1,explanation:"5 減去 2 等於 3。"},{id:6,section:"幼兒園高班",sectionName:"語文與認知",category:"字形辨析",question:"下面的字當中，哪一個是「山」字？",options:["水","石","山","土"],correctAnswer:2,explanation:"第三個選項是「山」字。"},{id:7,section:"幼兒園高班",sectionName:"邏輯與常識",category:"生活習慣",question:"吃東西之前，我們應該先做什麼？",options:["洗手","睡覺","看電視","唱歌"],correctAnswer:0,explanation:"為了衛生健康，吃東西前必須先洗手。"},{id:8,section:"幼兒園高班",sectionName:"基礎數學",category:"圖形認知",question:"太陽是什麼形狀的？",options:["正方形","三角形","圓形","長方形"],correctAnswer:2,explanation:"從視覺上看，太陽是圓形的。"},{id:9,section:"幼兒園高班",sectionName:"邏輯與常識",category:"色彩認知",question:"香蕉成熟的時候，通常是什麼顏色的？",options:["紅色","藍色","綠色","黃色"],correctAnswer:3,explanation:"成熟的香蕉外皮是黃色的。"},{id:10,section:"幼兒園高班",sectionName:"語文與認知",category:"詞語分類",question:"下面哪一個不是水果？",options:["蘋果","西瓜","西紅柿","青蛙"],correctAnswer:3,explanation:"青蛙是動物，不是水果。"},{id:11,section:"幼兒園高班",sectionName:"基礎數學",category:"數字排序",question:"在數字 6 和 8 的中間，應該填哪一個數字？",options:["5","7","9","10"],correctAnswer:1,explanation:"按順序數數是 6、7、8，所以中間是 7。"},{id:12,section:"幼兒園高班",sectionName:"邏輯與常識",category:"天氣與生活",question:"下雨天出門的時候，我們需要帶什麼？",options:["太陽眼鏡","雨傘","圍巾","泳衣"],correctAnswer:1,explanation:"下雨天需要帶雨傘來擋雨。"},{id:13,section:"幼兒園高班",sectionName:"語文與認知",category:"拼音/發音",question:"「b」和「a」拼在一起，讀作什麼？",options:["ba","ma","pa","fa"],correctAnswer:0,explanation:"聲母 b 和韻母 a 相拼讀作 ba。"},{id:14,section:"幼兒園高班",sectionName:"基礎數學",category:"比大小",question:"下面哪一個數字最大？",options:["3","6","9","2"],correctAnswer:2,explanation:"在 2、3、6、9 當中，9 是最大的數。"},{id:15,section:"幼兒園高班",sectionName:"邏輯與常識",category:"交通安全",question:"過馬路時，看到什麼顏色的燈才可以走？",options:["紅燈","黃燈","綠燈","藍燈"],correctAnswer:2,explanation:"綠燈行，紅燈停，所以綠燈才能過馬路。"},{id:16,section:"幼兒園高班",sectionName:"語文與認知",category:"反義詞",question:"「多」的反義詞是什麼？",options:["少","大","重","矮"],correctAnswer:0,explanation:"「多」和「少」是一對相反詞。"},{id:17,section:"幼兒園高班",sectionName:"基礎數學",category:"加法運算",question:"4 加 4 等於多少？",options:["6","7","8","9"],correctAnswer:2,explanation:"4 + 4 = 8。"},{id:18,section:"幼兒園高班",sectionName:"邏輯與常識",category:"身體器官",question:"我們用哪一個器官來聽聲音？",options:["眼睛","鼻子","嘴巴","耳朵"],correctAnswer:3,explanation:"耳朵是我們的聽覺器官。"},{id:19,section:"幼兒園高班",sectionName:"語文與認知",category:"量詞運用",question:"一（ ）書。括號裡應該填什麼？",options:["個","本","隻","支"],correctAnswer:1,explanation:"書本的量詞是「本」。"},{id:20,section:"幼兒園高班",sectionName:"基礎數學",category:"規律推理",question:"按照「圓形、三角形、圓形、三角形……」的規律，接下來是什麼圖形？",options:["圓形","三角形","正方形","星形"],correctAnswer:0,explanation:"規律是圓形和三角形交替，三角形後面又是圓形。"},{id:21,section:"幼兒園高班",sectionName:"邏輯與常識",category:"植物認知",question:"西瓜是長在哪裡的？",options:["大樹上","地上的藤蔓上","水裡面","泥土裡面"],correctAnswer:1,explanation:"西瓜是結在貼近地面的藤蔓上的。"},{id:22,section:"幼兒園高班",sectionName:"語文與認知",category:"漢字認讀",question:"「月」字通常會讓我們想到什麼？",options:["太陽","月亮","星星","白雲"],correctAnswer:1,explanation:"「月」就是月亮的意思。"},{id:23,section:"幼兒園高班",sectionName:"基礎數學",category:"減法運算",question:"我有 10 個氣球，不小心爆了 3 個，還剩幾個？",options:["5 個","6 個","7 個","8 個"],correctAnswer:2,explanation:"10 減去 3 等於 7。"},{id:24,section:"幼兒園高班",sectionName:"邏輯與常識",category:"生活常識",question:"一星期一共有幾天？",options:["5 天","6 天","7 天","8 天"],correctAnswer:2,explanation:"一星期有七天（星期一到星期日）。"},{id:25,section:"幼兒園高班",sectionName:"語文與認知",category:"詞語搭配",question:"下面哪一個詞語組合是最合理的？",options:["小魚在飛","小鳥在游","小馬在跑","小狗在寫字"],correctAnswer:2,explanation:"小馬擅長在地上奔跑，其他組合不符合自然現象。"},{id:26,section:"幼兒園高班",sectionName:"基礎數學",category:"空間方位",question:"小貓在桌子下面，小狗在桌子上面。哪隻動物在高處？",options:["小貓","小狗","一樣高","不知道"],correctAnswer:1,explanation:"在「上面」代表在比較高的地方。"},{id:27,section:"幼兒園高班",sectionName:"邏輯與常識",category:"時間認知",question:"我們通常在白天的什麼時候吃早餐？",options:["早上","中午","下午","晚上"],correctAnswer:0,explanation:"早晨起床後吃的第一餐叫做早餐。"},{id:28,section:"幼兒園高班",sectionName:"語文與認知",category:"偏旁部首",question:"「海、河、洗」這些字都有什麼共同的部分？",options:["單人旁","三點水","草字頭","木字旁"],correctAnswer:1,explanation:"這些字都帶有「氵」（三點水）偏旁，通常與水有關。"},{id:29,section:"幼兒園高班",sectionName:"基礎數學",category:"數的合成",question:"數字 5 可以由 1 和幾合成？",options:["2","3","4","5"],correctAnswer:2,explanation:"1 加上 4 等於 5。"},{id:30,section:"幼兒園高班",sectionName:"邏輯與常識",category:"職業認知",question:"生病的時候，是誰幫我們看病治病的？",options:["老師","警察","醫生","司機"],correctAnswer:2,explanation:"醫生的工作是幫病人看病和治療。"},{id:31,section:"幼兒園高班",sectionName:"語文與認知",category:"反義詞",question:"「長」的反義詞是什麼？",options:["短","高","新","遠"],correctAnswer:0,explanation:"「長」和「短」是一對相反詞。"},{id:32,section:"幼兒園高班",sectionName:"基礎數學",category:"圖形特徵",question:"正方形一共有幾條邊？",options:["3 條","4 條","5 條","6 條"],correctAnswer:1,explanation:"正方形是由 4 條一樣長的邊組成的圖形。"},{id:33,section:"幼兒園高班",sectionName:"邏輯與常識",category:"季節特徵",question:"哪一個季節會下雪，天氣最冷？",options:["春天","夏天","秋天","冬天"],correctAnswer:3,explanation:"冬天是一年當中最冷、部分地區會下雪的季節。"},{id:34,section:"幼兒園高班",sectionName:"語文與認知",category:"量詞運用",question:"一（ ）鉛筆。括號裡應該填什麼？",options:["支","把","張","朵"],correctAnswer:0,explanation:"細長條狀的書寫工具量詞用「支」。"},{id:35,section:"幼兒園高班",sectionName:"基礎數學",category:"20以內數數",question:"數字 19 後面的一個數是多少？",options:["18","20","21","22"],correctAnswer:1,explanation:"19 再往後數一個數就是 20。"},{id:36,section:"幼兒園高班",sectionName:"邏輯與常識",category:"動物特徵",question:"哪種動物的脖子最長？",options:["大象","長頸鹿","河馬","猴子"],correctAnswer:1,explanation:"長頸鹿以脖子長為顯著特徵。"},{id:37,section:"幼兒園高班",sectionName:"語文與認知",category:"詞語分類",question:"下面哪一個詞語屬於「文具」？",options:["皮球","橡皮擦","餅乾","衣服"],correctAnswer:1,explanation:"橡皮擦是用來擦錯字的文件，屬於文具。"},{id:38,section:"幼兒園高班",sectionName:"基礎數學",category:"簡單加法",question:"2 加上 0 等於多少？",options:["0","1","2","3"],correctAnswer:2,explanation:"任何數加上 0 都等於它自己。"},{id:39,section:"幼兒園高班",sectionName:"邏輯與常識",category:"安全常識",question:"當房間裡突然著火時，應該撥打什麼電話求助？",options:["110 / 999","119 / 999","120","114"],correctAnswer:1,explanation:"火警求助電話通常是119（內地）或999（香港），這裡指消防求助。"},{id:40,section:"幼兒園高班",sectionName:"語文與認知",category:"字義辨析",question:"「人」字加上一橫，會變成什麼字？",options:["大","天","太","木"],correctAnswer:0,explanation:"「人」字中間加一橫就是「大」字。"},{id:41,section:"幼兒園高班",sectionName:"基礎數學",category:"比輕重",question:"大象和螞蟻相比，誰比較重？",options:["大象","螞蟻","一樣重","不知道"],correctAnswer:0,explanation:"大象的身型巨大，遠比螞蟻重。"},{id:42,section:"幼兒園高班",sectionName:"邏輯與常識",category:"生活常識",question:"冰塊放到熱水裡，會發生什麼事？",options:["變得更大","融化成水","變成石頭","沒有變化"],correctAnswer:1,explanation:"冰塊受熱後會融化變成液態水。"},{id:43,section:"幼兒園高班",sectionName:"語文與認知",category:"反義詞",question:"「哭」的反義詞是什麼？",options:["笑","叫","跑","跳"],correctAnswer:0,explanation:"「哭」和「笑」表達相反的情緒。"},{id:44,section:"幼兒園高班",sectionName:"基礎數學",category:"數的分解",question:"把 6 個蘋果平均分給 2 個小朋友，每人分到幾個？",options:["2 個","3 個","4 個","5 個"],correctAnswer:1,explanation:"6 可以分成 3 和 3，所以每人分 3 個。"},{id:45,section:"幼兒園高班",sectionName:"邏輯與常識",category:"感知覺",question:"檸檬嚐起來是什麼味道的？",options:["甜的","辣的","酸的","鹹的"],correctAnswer:2,explanation:"檸檬含有豐富檸檬酸，味道很酸。"},{id:46,section:"幼兒園高班",sectionName:"語文與認知",category:"量詞運用",question:"一（ ）花。括號裡應該填什麼？",options:["朵","個","隻","條"],correctAnswer:0,explanation:"花朵的量詞用「朵」。"},{id:47,section:"幼兒園高班",sectionName:"基礎數學",category:"時鐘認知",question:"鐘錶上的長針（分針）走一圈，短針（時針）會走幾大格？",options:["1 格","2 格","5 格","12 格"],correctAnswer:0,explanation:"分針走一圈（60分鐘），時針走一大格（1小時）。"},{id:48,section:"幼兒園高班",sectionName:"邏輯與常識",category:"植物常識",question:"植物的生長需要陽光、土壤和什麼？",options:["牛奶","水","果汁","可樂"],correctAnswer:1,explanation:"水是植物生長必不可少的基本要素。"},{id:49,section:"幼兒園高班",sectionName:"語文與認知",category:"詞語搭配",question:"我們常說「（ ）高采烈」，括號裡應該填什麼字？",options:["興","心","新","星"],correctAnswer:0,explanation:"成語是「興高采烈」，意思是興致高、情緒熱烈。"},{id:50,section:"幼兒園高班",sectionName:"基礎數學",category:"連加運算",question:"1 加 2 再加 3 等於多少？",options:["4","5","6","7"],correctAnswer:2,explanation:"1 + 2 = 3，3 + 3 = 6。"}],o=Object.freeze(Object.defineProperty({__proto__:null,default:e},Symbol.toStringTag,{value:"Module"}));export{o as _};
